{"content":"import { motion } from 'framer-motion'
import { Trash2 } from 'lucide-react'
import { Checkbox } from './ui/Checkbox'
import { Label } from './ui/Label'
import { useTodoStore, Todo } from '../store/useStore'

interface TodoItemProps {
  todo: Todo
}

export const TodoItem = ({ todo }: TodoItemProps) => {
  const toggleTodo = useTodoStore((state) => state.toggleTodo)
  const deleteTodo = useTodoStore((state) => state.deleteTodo)

  return (
    <motion.div
      initial={{ opacity: 0, y: 10 }}
      animate={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0, scale: 0.95 }}
      layout
      className="flex items-center justify-between p-4 mb-2 bg-card rounded-lg border shadow-sm group"
    >
      <div className="flex items-center space-x-3">
        <Checkbox
          id={todo.id}
          checked={todo.completed}
          onCheckedChange={() => toggleTodo(todo.id)}
        />
        <Label
          htmlFor={todo.id}
          className={`text-lg cursor-pointer transition-all ${
            todo.completed ? 'line-through text-muted-foreground' : ''
          }`}
        >
          {todo.title}
        </Label>
      </div>
      <button
        onClick={() => deleteTodo(todo.id)}
        className="p-2 text-muted-foreground hover:text-destructive transition-colors opacity-0 group-hover:opacity-100"
      >
        <Trash2 className="h-5 w-5" />
      </button>
    </motion.div>
  )
}
